import { MinPriorityQueue } from 'datastructures-js/priority-queue';

function solve(n, edges) {
    // Build the graph: original edges and reversed edges (for possible flipping)
    const graph = new Map();
    const reversedEdges = new Map();

    for (const [u, v, w] of edges) {
        if (!graph.has(u)) {
            graph.set(u, []);
        }
        graph.get(u).push([v, w]);

        if (!reversedEdges.has(v)) {
            reversedEdges.set(v, []);
        }
        reversedEdges.get(v).push([u, w]);
    }

    // Dijkstra's setup: priority queue with (total_cost, current_node, used_flip)
    const heap = new MinPriorityQueue({
        priority: (entry) => entry[0]
    });
    heap.enqueue([0, 0, false]);

    // Visited tracks the minimal cost to reach each node with and without using flip
    const visited = new Map();
    visited.set(`${0},${false}`, 0);
    visited.set(`${0},${true}`, Infinity);

    while (!heap.isEmpty()) {
        const { element: [currentCost, u, usedFlip] } = heap.dequeue();
        if (u === n - 1) {
            return currentCost;
        }

        if (currentCost > (visited.get(`${u},${usedFlip}`) || Infinity)) {
            continue;
        }

        // Explore original edges
        if (graph.has(u)) {
            for (const [v, w] of graph.get(u)) {
                const newCost = currentCost + w;
                const key = `${v},${usedFlip}`;
                if (newCost < (visited.get(key) || Infinity)) {
                    visited.set(key, newCost);
                    heap.enqueue([newCost, v, usedFlip]);
                }
            }
        }

        // If flip hasn't been used, try flipping an incoming edge
        if (!usedFlip && reversedEdges.has(u)) {
            for (const [v, w] of reversedEdges.get(u)) {
                const newCost = currentCost + 2 * w;
                const key = `${v},${true}`;
                if (newCost < (visited.get(key) || Infinity)) {
                    visited.set(key, newCost);
                    heap.enqueue([newCost, v, true]);
                }
            }
        }
    }

    // Check if we can reach n-1 with or without flip
    const res = Math.min(
        visited.get(`${n-1},${false}`) || Infinity,
        visited.get(`${n-1},${true}`) || Infinity
    );
    return res !== Infinity ? res : -1;
}
